export function forExpression(
  patternOrConfig: NodeData<'string_literal' | 'raw_string_literal' | 'char_literal' | 'boolean_literal' | 'integer_literal' | 'float_literal' | 'negative_literal' | 'identifier' | 'scoped_identifier' | 'generic_pattern' | 'tuple_pattern' | 'tuple_struct_pattern' | 'struct_pattern' | 'ref_pattern' | 'slice_pattern' | 'captured_pattern' | 'reference_pattern' | 'remaining_field_pattern' | 'mut_pattern' | 'range_pattern' | 'or_pattern' | 'const_block' | 'macro_invocation'> | ForExpressionConfig,
  config?: Partial<ForExpressionConfig>,
): ForExpressionNode {
  const fields: any = isNodeData(patternOrConfig)
    ? { 'pattern': patternOrConfig, ...config }
    : patternOrConfig;
  const node: any = { type: 'for_expression', fields };
  node.value = (v: any) => { fields['value'] = v; return node; };
  node.body = (v: any) => { fields['body'] = v; return node; };
  node.children = (...v: any[]) => { fields.children = v; return node; };
  node.render = () => render(node, rules, joinBy);
  node.toEdit = (startOrRange: any, endPos?: number) => {
    if (typeof startOrRange === 'number') return toEdit(node, rules, startOrRange, endPos!, joinBy);
    return toEdit(node, rules, startOrRange, joinBy);
  };
  node.replace = (target: any) => { const r = target.range(); return toEdit(node, rules, r, joinBy); };
  return node;
}

forExpression.assign = function(target: AssignableNode<'for_expression'>): ForExpressionNode {
  const overrides: any = {};
  const fieldList: string[] = ['pattern', 'value', 'body'];
  const getFields = () => {
    const merged: any = {};
    for (const f of fieldList) {
      if (f in overrides) { merged[f] = overrides[f]; continue; }
      const child = target.field(f);
      if (child) merged[f] = { type: child.type, fields: {}, text: child.text() };
    }
    if ('children' in overrides) { merged.children = overrides.children; }
    else { merged.children = target.children().map(c => ({ type: c.type, fields: {}, text: c.text() })); }
    return merged;
  };
  const node: any = { get type() { return 'for_expression'; }, get fields() { return getFields(); } };
  node.pattern = (v: any) => { overrides['pattern'] = v; return node; };
  node.value = (v: any) => { overrides['value'] = v; return node; };
  node.body = (v: any) => { overrides['body'] = v; return node; };
  node.children = (...v: any[]) => { overrides.children = v; return node; };
  node.render = () => render(node, rules, joinBy);
  node.toEdit = () => {
    const r = target.range();
    return { startPos: r.start.index, endPos: r.end.index, insertedText: node.render() };
  };
  node.replace = node.toEdit;
  return node;
} as any;

